SERVICES=[
('organization-design','顶层设计与组织机制','让发展方向、经营责任与利益机制形成一致。',['商业模式与战略优化','股权结构与公司治理','动态合伙与内部创业','薪酬绩效与股权激励']),
('process-redesign','流程与组织再造','把个人经验转化为可以复制、协同和持续改善的组织能力。',['关键业务流程诊断','流程蓝图与职责重构','协作、权限与指标设计','流程标准化与落地辅导']),
('enterprise-ai','企业 AI 与数字化导入','让 AI 进入关键岗位和经营流程，以可验证结果推动转型。',['AI 应用场景诊断','数字员工与工作流设计','企业知识库与零代码系统','运营指标与持续迭代']),
('advisory','长期管理顾问与陪跑','为增长与转型期企业提供持续决策支持和实施推动。',['经营与组织复盘','重大决策支持','关键项目推动','管理团队教练'])]
CASES=[
('industrial-equity','工业制造','股权架构重组与员工激励计划改造','原有激励与经营责任脱节，缺少清晰的业绩条件、责任边界和退出规则。','企业真正需要的不是一次性分股，而是从岗位绩效、业务单元分红到长期股权的渐进式激励路径。','organization-design'),
('medical-partnership','医疗健康','商业模式与合伙型组织顶层设计','新业务引入多类资源伙伴，各方对投入、决策、收益与长期发展缺少统一认识。','先明确业务模式、核心能力、合作角色和阶段贡献，再决定治理、分配和股权安排。','organization-design'),
('education-digital-process','教育服务','业务流程数字化与组织调整','销售、收款、交付和售后依赖个人微信，一人承担全流程导致服务能力受限。','需要同时调整岗位分工、服务标准、信息沉淀与异常处理，而不只是增加客服工具。','process-redesign'),
('manufacturing-sales-agent','ToB 制造','销售全流程数字员工导入','客户研究、提案材料和失败复盘分散在网页、群聊与个人电脑。','企业需要一条从机会发现到知识沉淀的销售工作流，而不是单个文案助手。','enterprise-ai'),
('new-energy-ecosystem','新能源科技','上下游生态合伙机制设计','企业希望整合渠道、技术和资源伙伴，传统采购与一次性佣金难以形成长期合作。','不同伙伴的投入和持续贡献不同，需要分层、分阶段的合作与权益机制。','organization-design'),
('service-operation-rhythm','专业服务','经营节奏与管理团队责任体系重构','业务增长依赖创始人推动，部门负责人关注任务，却缺少经营结果责任。','问题来自目标、核算、授权和复盘节奏缺失，而不是管理者态度不积极。','advisory')]
CATS=[('organization','组织效能'),('partnership','合伙与激励'),('human-resources','组织与人才'),('process','流程与经营'),('ai-transformation','企业 AI'),('consultant-notes','顾问手记')]
ARTS=[
('organization','what-is-organization-effectiveness','组织效能不是管理制度的数量，而是经营系统的运行质量','企业是否高效，最终要看方向能否转化为行动、责任能否转化为结果、经验能否沉淀为能力。','组织效能首先是经营问题|谈到组织效能，很多企业首先想到组织架构、岗位说明书和绩效考核。但制度只是载体，组织效能最终体现在能否以合理成本、稳定质量和足够速度实现经营目标。|如果方向不清，再精细的绩效指标也只能让团队更努力地走向不同方向。;判断组织效能的五个层次|第一看方向，第二看治理，第三看组织，第四看流程，第五看工具。这五层逐层承接，上层没有解决的问题，往往会在下层表现为人员和执行问题。|组织改善可以先选择一个影响收入、交付或现金流的关键问题，沿着目标、责任、流程、数据和工具向下追溯。'),
('organization','owner-dependency','老板越来越忙，通常意味着组织没有完成责任升级','创始人亲自推动一切并不等于负责，可能意味着经营责任没有真正转移到组织。','忙碌背后的结构问题|企业早期依靠创始人快速决策是优势，但随着业务增加，所有信息、审批和资源都汇集到老板，就会形成新的瓶颈。|表面上是团队能力不足，深层原因往往是目标没有分解为业务责任、负责人没有足够权限。;责任升级的三个条件|负责人必须清楚对什么结果负责，获得与责任匹配的资源和决策权，结果还必须能够被持续衡量并与利益连接。|真正的组织升级，是老板仍然重要，但不再成为所有事情必须经过的节点。'),
('partnership','partnership-is-responsibility','合伙机制不是分钱方案，而是经营责任机制','只有把责任、权利、利益和退出连接起来，合伙才可能长期运行。','先谈责任，再谈比例|很多合伙讨论从股权比例开始，却没有先回答未来谁承担什么经营责任。股权可以确认长期关系，但不能替代业务模式、角色分工和经营规则。|没有责任基础的股权，容易把不确定的合作提前固化。;四个必须同时存在的机制|合伙至少需要责任、决策、利益和退出机制。只设计分配而忽略退出，会把短期贡献变成永久权利。|好的机制不是预测所有未来，而是让变化发生时有规则可循。'),
('partnership','progressive-equity-incentive','中小企业更适合渐进式股权激励','从奖金、超额分红、虚拟权益到注册股，让长期权益与经营能力同步成熟。','为什么不宜一步到位|股权具有较强稳定性，但员工的能力、意愿和岗位价值仍在变化。过早授予注册股，可能用永久权益奖励阶段性贡献。|中小企业更需要通过分阶段安排降低试错成本。;一条可行的激励阶梯|先用岗位绩效和项目奖金验证结果，再用超额利润分享建立经营意识，然后用虚拟股或跟投检验长期承诺，条件成熟后再考虑注册股。|激励的目标，是让核心人才逐步承担经营责任。'),
('human-resources','performance-system-root','企业真正缺少的，往往不是一套新的绩效制度','绩效问题经常源于经营责任、业务核算和跨部门协同。','绩效为什么反复重做|很多企业每年调整指标和权重，但员工仍认为考核不公平，管理者仍觉得绩效没有推动结果。|原因在于绩效被当成独立工具，没有连接企业目标、岗位责任和数据基础。;三个前置问题|部门究竟对什么经营结果负责，这个结果能否被合理核算，部门之间的共同责任如何划分。|绩效应帮助团队识别重点、反馈差距和推动改善，而不仅是计算奖金。'),
('human-resources','responsibility-right-benefit','责任、权利和利益不匹配，是管理内耗的重要来源','要求管理者承担结果，就必须同时配置决策权、资源和与结果相连的收益。','常见的三种错位|有责任没有权利，有权利没有责任，或者责任权利存在却与利益完全无关。这些错位会让组织依赖向上请示和临时推动。|管理者需要对一组相互关联的结果负责，而不是一串分散任务。;机制必须可运行|企业需要通过经营复盘观察规则是否促进了正确行为，再根据业务变化调整。|机制的价值不在文件完整，而在减少模糊地带和反复协调。'),
('process','process-redesign-not-flowchart','流程再造不是画流程图，而是重新设计价值如何流动','真正的流程改善会同时改变岗位责任、决策权限、数据标准和协作方式。','流程图为什么没有效果|如果只是把现有做法原样画出来，流程图最多帮助大家看见复杂，却不会自动消除复杂。|流程再造要从客户价值和经营结果反向审视每个活动。;流程与组织必须一起改|流程横跨多个岗位，任何节点变化都会影响责任、能力、权限和指标。只改步骤不改组织，员工仍会按旧的权责关系工作。|数字化系统必须建立在目标流程之上，否则只会把低效流程固化得更快。'),
('process','management-rhythm','经营节奏，是把战略转化为日常行动的基础设施','周、月、季度复盘让信息、判断、行动和责任形成闭环。','战略为什么落不到日常|年度目标很宏大，但团队每天面对客户、交付、人员和现金流。如果缺少固定节奏，重要事项容易被紧急事项覆盖。|经营节奏在不同时间尺度上处理不同问题。;不同会议解决不同问题|周度关注异常和短期行动，月度关注经营结果和资源调整，季度关注战略假设和组织能力。|AI 可以协助汇总数据和跟踪行动，但管理者仍需做价值判断。'),
('ai-transformation','ai-failure-is-workflow','AI 工具导入失败，通常不是模型能力不够','没有触发条件、输入输出、权限、日志和兜底，AI 就无法成为稳定工作流。','从工具体验到业务结果|员工试用 AI 时常常觉得惊艳，但几周后使用频率下降。原因是工具与真实任务之间仍需要大量人工判断和资料准备。|企业需要明确什么时候调用、需要什么输入、输出交给谁、如何检查。;数字员工的六个组成部分|可运行的数字员工包括触发条件、标准输入、处理规则、结构化输出、权限日志和失败兜底。|企业应先选择一到三个高频、规则清晰、结果可验证的场景快速跑通。'),
('ai-transformation','ai-scenario-priority','企业选择 AI 场景，应当先算业务账','优先处理高频、高成本、高延迟、可标准化且结果可验证的工作。','不要从模型功能出发|如果先看 AI 能做什么，企业容易积累大量演示场景，却无法确定投入优先级。|更有效的方法是从收入、成本、周期、质量和风险出发。;五个筛选维度|评估发生频率、人工成本、业务影响、标准化程度和结果可验证性，同时考虑数据、权限与人工复核成本。|AI 转型是组织持续发现、设计和运营工作流的能力。'),
('consultant-notes','from-symptom-to-root','客户提出的问题，往往不是最终需要解决的问题','顾问的价值，是区分表面症状、直接原因与真正约束企业发展的结构问题。','不要急着回答|客户说需要绩效方案、股权激励或 AI 系统时，直接进入方案设计可能在错误问题上投入更多资源。|需要追问为什么现在提出问题、哪些结果没有发生、过去尝试过什么。;从现象到结构|员工积极性不足可能来自目标不清、授权不足或核算失真；服务效率低可能来自岗位分工和信息断点。|最好的方案不是理论上最完整，而是当前团队有能力执行。'),
('consultant-notes','consulting-delivery','咨询交付的终点，不是方案通过，而是组织开始用新方式工作','方案文件只是中间成果，真正的交付发生在共识、行动、反馈和调整之中。','为什么方案会停在文件里|方案可能逻辑严密，却没有进入管理者日常决策。常见原因是核心团队没有参与形成方案，也没有明确第一批要改变的行为。|制度发布并不等于机制运行。;把实施纳入设计|设计方案时就要考虑谁推动、从哪里试点、用什么数据判断效果、遇到阻力如何调整。|当团队掌握发现问题和持续改善的方法，咨询成果才转化为组织能力。')]
