def foot():return '<footer><div class="container"><div class="footer-grid"><div><a class="brand" href="{R}index.html"><span class="brand-mark">相</span><span>张相波 · 组织效能顾问</span></a><p>帮助成长型中小企业重新连接战略、组织、机制、流程与 AI。</p></div><div><h4>专业内容</h4><div class="footer-links"><a href="{R}services/index.html">专业服务</a><a href="{R}cases/index.html">代表案例</a><a href="{R}insights/index.html">洞察与手记</a><a href="{R}projects/index.html">项目与资源</a></div></div><div><h4>联系与合作</h4><div class="footer-links"><a href="mailto:me@xiangbo.net">me@xiangbo.net</a><a href="{R}diagnosis/index.html">申请组织效能诊断</a><a href="{R}contact/index.html">企业内训与商务合作</a><a href="{R}privacy/index.html">隐私说明</a></div></div></div><div class="copyright">© 2026 xiangbo.net · 励拓咨询（深圳）有限公司</div></div></footer>'
def page(path,title,desc,body,active=''):
 p=prefix(path); html=f'<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="description" content="{escape(desc)}"><title>{escape(title)}｜张相波</title><link rel="stylesheet" href="{p}assets/style.css"></head><body>{nav(active)}<main>{body}</main>{foot()}<script src="{p}assets/site.js"></script></body></html>'.replace('{R}',p); out=R/path;out.parent.mkdir(parents=True,exist_ok=True);out.write_text(html,encoding='utf-8')
def hero(k,t,s,a=''):return f'<section class="page-hero"><div class="container page-grid"><div><p class="eyebrow">{k}</p><h1>{t}</h1><p class="lead">{s}</p></div>'+ (f'<aside class="aside">{a}</aside>' if a else '')+'</div></section>'
