# verify links
from bs4 import BeautifulSoup
errs=[]
for p in htmls:
 soup=BeautifulSoup(p.read_text(encoding='utf-8'),'html.parser')
 for tag in soup.find_all(['a','link','script']):
  u=tag.get('href' if tag.name!='script' else 'src','')
  if not u or u.startswith(('http','mailto:','#')):continue
  if not (p.parent/u.split('#')[0]).resolve().exists():errs.append(f'{p.relative_to(R)} -> {u}')
if errs:raise SystemExit('\n'.join(errs))
with zipfile.ZipFile('/data/xiangbo-net-complete.zip','w',zipfile.ZIP_DEFLATED) as z:
 for p in R.rglob('*'):
  if p.is_file():z.write(p,p.relative_to(R.parent))
